begin;
-- Repair Mobility & Stability workouts: remove high-impact, heavy-strength, and crunch/leg-raise movements.
update public.admin_workouts set main_workout = $mobility_repair$<p class="tiptap-paragraph">🧽 <strong><u>Soft Tissue Preparation 5'</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph">Lacrosse ball upper trap release (45 seconds per side)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">Foam roll hip flexors (45 seconds per side)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">Lacrosse ball glute trigger points (45 seconds per side)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">Foam roll calves with pauses (30 seconds per leg)</p></li></ul><p class="tiptap-paragraph"></p><p class="tiptap-paragraph">🔥 <strong><u>Activation (8 minutes)</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph"><strong>1. Cat Stretch – Arch and round spine, coordinating with inhale/exhale – 60 seconds</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph"><strong>3. Bird with Resistance Band</strong> – Opposite arm/leg extension, band jack knife sit-up – 10 reps each side</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph"><strong>4. scapula dips – Full range of motion for shoulder blades – 30 seconds each side</p></li></ul><p class="tiptap-paragraph"><strong>2. Thoracic Rotations</strong> – Quadruped, exercise ball back extension with hands behind head, rotate elbow to ceiling – 30 seconds each side</p><p class="tiptap-paragraph"><strong>5. Ankle Dorsiflexion with Band</strong> – Seated, band around foot, pull toes towards shin – 15 reps each side</p><p class="tiptap-paragraph"></p><p class="tiptap-paragraph">💪 <strong><u>Main Workout (45 minutes)</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph"><strong>1. {{exercise:1604:world greatest stretch}} – Maintain balance on one leg, hold dumbbell, other leg on stability ball – 8-10 reps each leg</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph"><strong>2. {{exercise:1268:cable press on exercise ball}} – Kneeling, press band away from chest, resist rotation – 12-15 reps each side</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph"><strong>3. {{exercise:1775:side plank hip adduction}} – Hold side plank, abduct top leg against band resistance – 10-12 reps each side</p></li></ul><p class="tiptap-paragraph">Rest: 60-90 seconds between rounds.</p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph"><strong>2. {{exercise:0243:cable twist}} – Powerful diagonal chop across body – 10-12 reps each direction</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph"><strong>3. {{exercise:0971:band assisted wheel rollerout}} – Kneeling, roll ball forward, maintain plank position – 12-15 reps</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:0551:kettlebell turkish get up (squat style)}} (squat style) (squat style) (squat style) (squat style) – Controlled movement from lying to standing and back – 3-4 reps each side</p></li></ul><p class="tiptap-paragraph">Rest: 60-90 seconds between rounds.</p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph"><strong>Block 3: {{exercise:2207:roller side lat stretch}}</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph"><strong>1. {{exercise:3643:weighted cossack squats (male)}} – Deep lateral squat, maintaining chest upright – 6-8 reps each side</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:3523:glute bridge two legs on bench (male)}} – Band around knees, skater hops, drive hips up – 15-20 reps</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph"><strong>3. {{exercise:0978:band front raise}} – Back against wall, band front raise, slide arms up and down – 15-20 reps</p></li></ul><p class="tiptap-paragraph">Rest: 45-60 seconds between rounds.</p><p class="tiptap-paragraph"></p><p class="tiptap-paragraph">⚡ <strong><u>Finisher</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph">20 {{exercise:high-knees:high-knees}}</p></li></ul><p class="tiptap-paragraph">Complete 3 rounds:</p><p class="tiptap-paragraph"></p><p class="tiptap-paragraph">🧘 <strong><u>Cool (7 minutes)</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph"><strong>1. push-up – Lie prone, use ball to support leg for deeper stretch – 60 seconds each leg</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph"><strong>3. Pigeon Stretch – Deep hip opener, hold and breathe – 60 seconds each side</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">russian twist – Lie on back</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">mountain climber, look opposite way – 60 seconds each side</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph"><strong>5. Diaphragmatic Breathing</strong> – Lie on back, hands bike, focus on deep slow breaths – 120 seconds</p></li></ul>$mobility_repair$, updated_at = now() where id = 'WOD-MS-EQ-1765170005436';
update public.admin_workouts set main_workout = $mobility_repair$<p class="tiptap-paragraph">🧽 <strong><u>Soft Tissue Preparation 5'</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph">Lacrosse ball rhomboid release (45 seconds per side)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">Foam roll IT band with pauses (45 seconds per leg)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">Lacrosse ball hip flexor release (45 seconds per side)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">Foam roll ankle mobility prep (30 seconds per leg)</p></li></ul><p class="tiptap-paragraph"></p><p class="tiptap-paragraph">🔥 <strong><u>Activation 10'</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph">Cat Stretch – 3 sets x 10 reps (slow, controlled)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">three bench dip – 3 sets x 8 reps per side (hold stretch for 2-3 seconds)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">wrist circles– 2 sets x 10 clockwise, 10 counter-clockwise per leg</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">shoulder tap push-up– 2 sets x 5 reps per arm (large, slow circles)</p></li></ul><p class="tiptap-paragraph"></p><p class="tiptap-paragraph"><p class="tiptap-paragraph">💪 <strong><u>Main Workout (Reps & Sets)</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:2571:rocking frog stretch}} – 4 sets x 8 reps per side. Focus on depth and full rotation. Rest 60 seconds.</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:0705:side bridge v. 2}} – 3 sets x 30 seconds per side. Maintain perfect plank form. Rest 45 seconds.</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:1259:behind head chest stretch}} – 3 sets x 45 seconds per side. Actively rotate through the rib cage. Rest 30 seconds.</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:3021:scapula push-up}}– 4 sets x 12 reps. Control movement at the shoulder blade. Rest 60 seconds.</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:0996:band seated hip internal rotation}} – 3 sets x 8 reps per side. Maintain core tension throughout the bear crawl and reach. Rest 45 seconds.</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:1604:world greatest stretch}} – 3 sets x 10 reps per leg. Go slow, maintain balance, achieve full range. Rest 60 seconds.</p></li></ul><p class="tiptap-paragraph"></p>🧘 <strong><u>Cool Down 5'</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph">russian twist – 30 seconds each side</p></li></ul>$mobility_repair$, updated_at = now() where id = 'WOD-MS-E-1766026160083';
update public.admin_workouts set main_workout = $mobility_repair$<p class="tiptap-paragraph">🧽 <strong><u>Soft Tissue Preparation 5'</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph">Tennis ball / self-massage glutes & TFL — 45 sec each side</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">Tennis ball / self-massage quadriceps — 45 sec each leg</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">Tennis ball / self-massage lats — 30 sec each side</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">Thoracic spine extensions over foam roller — 8–10 reps</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">Tennis ball / self-massage calves — 30 sec each leg</p></li></ul><p class="tiptap-paragraph">🔥 <strong><u>Activation 10'</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph">30 seconds {{exercise:3672:back and forth step}}</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">30 seconds {{exercise:1368:ankle circles}}</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">30 seconds {{exercise:1428:wrist circles}}</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">10 {{exercise:cat-cow-stretch:Cat-Cow Stretch}}</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">8 {{exercise:bird-dog:Bird Dog}}</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">10 {{exercise:3013:low glute bridge on floor}}</p></li></ul><p class="tiptap-paragraph"></p><p class="tiptap-paragraph">💪 <strong><u>Main Workout (REPS & SETS)</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph">3 {{exercise:glute-bridge:Glute Bridge}} (pause at top)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">3 {{exercise:forearm-plank:Forearm Plank}} (controlled movement)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">3 {{exercise:0865:lying leg-hip raise}} (bent knee) (slow and controlled)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">3 {{exercise:0710:side hip abduction}} (body weight)</p></li></ul><p class="tiptap-paragraph">Rest 60-90 seconds between sets.</p><p class="tiptap-paragraph"></p><p class="tiptap-paragraph">⚡ <strong><u>Finisher (REPS & SETS)</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph">3 {{exercise:0276:dead bug}} (alternate sides)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">3 {{exercise:1419:iron cross stretch}}</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">3 {{exercise:2329:spine twist}}</p></li></ul><p class="tiptap-paragraph">Rest 45-60 seconds between sets.</p><p class="tiptap-paragraph"></p><p class="tiptap-paragraph">🧘 <strong><u>Cool Down 10'</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:1511:hamstring stretch}}</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:1494:butterfly yoga pose}}</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:1424:seated glute stretch}}</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph"><strong>Diaphragmatic Breathing (2 min):</strong> Lie supine, one hand on chest , one on belly. Slow inhale through nose (belly rises), slow exhale through mouth. Focus on calming nervous system.</p></li></ul>$mobility_repair$, updated_at = now() where id = 'WOD-MS-B-1777860745263';
update public.admin_workouts set main_workout = $mobility_repair$<p class="tiptap-paragraph">🧽 <strong><u>Soft Tissue Preparation 5'</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph">Foam roll upper back with arm reach (60 seconds)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">Lacrosse ball pec minor release (45 seconds per side)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">Foam roll quadriceps slowly (45 seconds per leg)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">Lacrosse ball piriformis release (45 seconds per side)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">Foam roll plantar fascia with ball (30 seconds per foot)</p></li></ul><p class="tiptap-paragraph"></p><p class="tiptap-paragraph">🔥 <strong><u>Activation 10'</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:1167:dynamic chest stretch (male)}}- 10 reps each side (2 minutes)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:0998:band side triceps extension}} - 10 reps (2 minutes)</p></li></ul><p class="tiptap-paragraph"></p><p class="tiptap-paragraph">💪 <strong><u>Main Workout 40'</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:0551:kettlebell turkish get up (squat style)}}- 3 sets x 50 ft each arm (Hold for stability, slow controlled steps)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:0854:weighted standing hand squeeze}} (Pinch two plates together) - 3 sets x Max hold time (Aim for 30-60 seconds)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:0984:band lying hip internal rotation}} - 3 sets x 15 reps each side (Controlled opening and closing against band tension)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:0979:band horizontal pallof press}}- 3 sets x 10 reps each side (Controlled power, focus on trunk rotation)</p></li></ul><p class="tiptap-paragraph"></p><p class="tiptap-paragraph">⚡ <strong><u>Finisher 10'</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:3665:power point plank}}</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:0710:side hip abduction}} - 2 sets x 10 reps each side (Slow and controlled leg lift)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:0979:band horizontal pallof press}} - 2 sets x 12 reps each side (Hold the end position for 2 seconds without trunk rotation)</p></li></ul><p class="tiptap-paragraph"></p><p class="tiptap-paragraph">🧘 <strong><u>Cool Down 10'</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:pigeon-stretch:Pigeon Stretch}} - 2 minutes each side</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:0979:band horizontal pallof press}} - 1 minute each side</p></li></ul>$mobility_repair$, updated_at = now() where id = 'WOD-MS-E-1767479405871';
update public.admin_workouts set main_workout = $mobility_repair$<p class="tiptap-paragraph">🧽 <strong><u>Soft Tissue Preparation 5'</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph">Foam roll quads and hamstrings (60 sec per area)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">Lacrosse ball glutes and hip flexors (60 sec per area)</p></li></ul><p class="tiptap-paragraph"></p><p class="tiptap-paragraph">🔥 <strong><u>Activation 10'</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph">2 {{exercise:1428:wrist circles}} (each direction)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">2 {{exercise:1364:standing pelvic tilt}}</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">2 {{exercise:1775:side plank hip adduction}} (male)</p></li></ul><p class="tiptap-paragraph"></p><p class="tiptap-paragraph">💪 <strong><u>Main Workout (REPS & SETS)</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph">3 {{exercise:0597:lever seated hip abduction}}</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">3 {{exercise:0598:lever seated hip adduction}}</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">3 {{exercise:1604:world greatest stretch}}</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">3 {{exercise:0573:lever back extension}}</p></li></ul><p class="tiptap-paragraph">Rest 60-90 seconds between sets.</p><p class="tiptap-paragraph"></p><p class="tiptap-paragraph">⚡ <strong><u>Finisher (REPS & SETS)</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph">2 {{exercise:3006:resistance band seated hip abduction}}</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">2 {{exercise:0979:band horizontal pallof press}} (each side)</p></li></ul><p class="tiptap-paragraph">Rest 45-60 seconds between sets.</p><p class="tiptap-paragraph"></p><p class="tiptap-paragraph">🧘 <strong><u>Cool Down 10'</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:1712:assisted side lying adductor stretch}}</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:1709:assisted lying glutes stretch}}</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:1713:assisted prone lying quads stretch}}</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:1346:kneeling lat stretch}}</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph"><strong>Diaphragmatic Breathing (2 min):</strong> Lie supine, one hand on chest , one on belly. Slow inhale through nose (belly rises), slow exhale through mouth. Focus on calming nervous system.</p></li></ul>$mobility_repair$, updated_at = now() where id = 'WOD-MS-E-1777860769226';
update public.admin_workouts set main_workout = $mobility_repair$<p class="tiptap-paragraph">🧽 <strong><u>Soft Tissue Preparation 5'</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph">Foam roll hip flexors and quads (30-45 sec per side)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">Foam roll hamstrings and glutes (30-45 sec per side)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">Foam roll upper back and lats (30-45 sec per side)</p></li></ul><p class="tiptap-paragraph"></p><p class="tiptap-paragraph">🔥 <strong><u>Activation 15'</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph">3 {{exercise:0257:circles knee stretch}} (each side)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">3 {{exercise:clamshell:Clamshell}} (each side)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">3 {{exercise:bird-dog:Bird Dog}} (each side)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">2 {{exercise:1471:inchworm}}</p></li></ul><p class="tiptap-paragraph"></p><p class="tiptap-paragraph">💪 <strong><u>Main Workout (REPS & SETS)</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph">3 {{exercise:0597:lever seated hip abduction}} (controlled tempo)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">3 {{exercise:0598:lever seated hip adduction}} (controlled tempo)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">3 {{exercise:1604:world greatest stretch}} (slow and controlled)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">3 {{exercise:0573:lever back extension}} (controlled, full range)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">3 {{exercise:1011:band seated twist}} (controlled, focus on scapular retraction)</p></li></ul><p class="tiptap-paragraph">Rest 60-90 seconds between sets.</p><p class="tiptap-paragraph"></p><p class="tiptap-paragraph">⚡ <strong><u>Finisher (REPS & SETS)</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph">3 {{exercise:forearm-plank:Forearm Plank}} (hold strong)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">3 {{exercise:glute-bridge:Glute Bridge}} (pause at the top)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">3 {{exercise:0756:smith hip raise}} (bent knee) (slow and controlled)</p></li></ul><p class="tiptap-paragraph">Rest 45-60 seconds between sets.</p><p class="tiptap-paragraph"></p><p class="tiptap-paragraph">🧘 <strong><u>Cool Down 10'</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:1511:hamstring stretch}}</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:1576:leg up hamstring stretch}}</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:1713:assisted prone lying quads stretch}}</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:1424:seated glute stretch}}</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:1363:spine stretch}}</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph"><strong>Diaphragmatic Breathing (2 min):</strong> Lie supine, one hand on chest , one on belly. Slow inhale through nose (belly rises), slow exhale through mouth. Focus on calming nervous system.</p></li></ul>$mobility_repair$, updated_at = now() where id = 'WOD-MS-E-1777864075367';
update public.admin_workouts set main_workout = $mobility_repair$<p class="tiptap-paragraph">🧽 <strong><u>Soft Tissue Preparation 5'</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph">Foam roll upper back with arm reach (60 seconds)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">Lacrosse ball pec minor release (45 seconds per side)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">Foam roll quadriceps slowly (45 seconds per leg)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">Lacrosse ball piriformis release (45 seconds per side)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">Foam roll plantar fascia with ball (30 seconds per foot)</p></li></ul><p class="tiptap-paragraph"></p><p class="tiptap-paragraph">🔥 <strong><u>Activation (7 minutes)</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph"><strong>1. cable low fly – Seamlessly transition between spinal flexion and extension, coordinating with your breath. – 1 minute</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph"><strong>3. dynamic chest stretch (male) – Enter a pigeon pose, then gently rock forward and back, feeling the stretch in your glutes and hips. – 30 seconds per side</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph"><strong>4. scapula dips – Isolate your shoulder blades, performing slow circles in all directions to mobilize the scapulothoracic joint. – 1 minute</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph"><strong>5. ankle circles – In a seated position, lift one foot and slowly rotate your ankle through its full range of motion. – 30 seconds per side</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">single leg bridge with outstretched leg – Stand on one leg</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">cable standing calf raise</p></li></ul><p class="tiptap-paragraph"><strong>2. Thoracic Rotations (Kneeling)</strong> – From a kneeling position, place one hand behind your head and rotate your upper back, opening your chest towards the ceiling. – 30 seconds per side</p><p class="tiptap-paragraph"></p><p class="tiptap-paragraph">💪 <strong><u>Main Workout (38 minutes)</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:3419:l-sit on floor}} – Start from a tucked L-sit</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:0108:barbell standing leg calf raise}} maintaining strong core engagement. – 20-30 seconds</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph"><strong>2. {{exercise:0705:side bridge v. 2}} – Perform a deep Cossack squat, then transition into a side plank on the same side, focusing on control. – 6-8 reps per side</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:1362:sphinx}} – From a loaded beast position, articulate your spine into an upward dog</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:1011:band seated twist}}</p></li></ul><p class="tiptap-paragraph">Rest: 60 seconds between rounds.</p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph"><strong>1. {{exercise:3470:forward lunge (male)}} – Perform a SLRDL, and at the bottom, rotate your torso towards the standing leg. – 8-10 reps per side</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph"><strong>2. {{exercise:bird-dog:Bird Dog}}}} – Hold a high plank, perform alternating shoulder taps, then extend one arm and rotate into a scorpion-like reach. – 6-8 reps per side (full combo)</p></li></ul><p class="tiptap-paragraph"><strong>3. push-up – Execute a dive bomber push-up-up-up-up, then push through your hands into a deep cobra stretch. – 6-8 reps</p><p class="tiptap-paragraph">Rest: 75 seconds between rounds.</p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph"><strong>1. {{exercise:3302:handstand}} – Face a wall, walk your feet up, hold for 10-15 seconds, then slowly lower. Focus on controlled descent. – 3-4 attempts</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph"><strong>2. {{exercise:2571:rocking frog stretch}} – Perform a deep single-leg squat. Use a wall or towel for assistance if full depth is challenging. – 5-7 reps per side</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:3639:bent knee lying twist (male)}} – Execute the full Turkish Get sequence without external weight, focusing on segmental control. – 3-4 reps per side</p></li></ul><p class="tiptap-paragraph">Rest: 90 seconds between rounds.</p><p class="tiptap-paragraph"></p><p class="tiptap-paragraph">⚡ <strong><u>Finisher</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph">20 {{exercise:high-knees:high-knees}}</p></li></ul><p class="tiptap-paragraph">Complete 3 rounds:</p><p class="tiptap-paragraph"></p><p class="tiptap-paragraph">🧘 <strong><u>Cool (5 minutes)</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph">russian twist – Lying on your back, extend arms to a 'T'</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">hug knees to chest and guide it across your body for a gentle twist. – 1 minute per side</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph"><strong>3. Deep Abdominal Breathing (Diaphragmatic)</strong> – Lie on your back, band reverse fly, and focus on slow, deep breaths, expanding your diaphragm. – 2 minutes</p></li></ul>$mobility_repair$, updated_at = now() where id = 'WOD-MS-BW-1765170005436';
update public.admin_workouts set main_workout = $mobility_repair$<p class="tiptap-paragraph">🧽 <strong><u>Soft Tissue Preparation 5'</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph">Foam roll glutes & TFL — 45 sec each side</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">Foam roll quadriceps — 45 sec each leg</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">Foam roll lats — 30 sec each side</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">Thoracic spine extensions over foam roller — 8–10 reps</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">Foam roll calves — 30 sec each leg</p></li></ul><p class="tiptap-paragraph">🔥 <strong><u>Activation 15'</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:clamshell:Clamshell}}</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:fire-hydrant:Fire Hydrant}}</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:bird-dog:Bird Dog}}</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:cat-cow-stretch:Cat-Cow Stretch}}</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:1471:inchworm}}</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:1685:squat to overhead reach}}</p></li></ul><p class="tiptap-paragraph"></p><p class="tiptap-paragraph">💪 <strong><u>Main Workout (REPS & SETS 30')</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:0517:kettlebell advanced windmill}} - 4 sets x 5-8 reps per side (4-1-1-0 tempo)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:1775:side plank hip adduction}} - 4 sets x 8-10 reps per side (controlled tempo)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:0551:kettlebell turkish get up (squat style)}}- 3 sets x 3-5 reps per side (controlled & deliberate)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:3664:dumbbell side plank with rear fly}} - 3 sets x 6-8 reps per side (slow & controlled)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:0805:suspended abdominal fallout}} - 3 sets x 10-12 reps (controlled negative)</p></li></ul><p class="tiptap-paragraph">Rest 60-90 seconds between sets.</p><p class="tiptap-paragraph"></p><p class="tiptap-paragraph">⚡ <strong><u>Finisher (REPS & SETS 20')</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:0866:weighted hanging leg-hip raise}} - 3 sets x 10-12 reps (controlled, focus on hip flexor stability)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:0979:band horizontal pallof press}} - 3 sets x 10-12 reps (focus on slow, controlled movement)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:0554:kettlebell windmill}} - 3 sets x 8-10 reps per side (lighter weight, focus on fluidity)</p></li></ul><p class="tiptap-paragraph">Rest 60 seconds between sets.</p><p class="tiptap-paragraph"></p><p class="tiptap-paragraph">🧘 <strong><u>Cool Down 10'</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:1424:seated glute stretch}}</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:1511:hamstring stretch}}</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:1713:assisted prone lying quads stretch}}</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:1363:spine stretch}}</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph"><strong>Diaphragmatic Breathing (2 min):</strong> Lie supine, one hand on chest, one on belly. Slow inhale through nose (belly rises), slow exhale through mouth. Focus on calming nervous system.</p></li></ul>$mobility_repair$, updated_at = now() where id = 'WOD-MS-E-1777156203085';
update public.admin_workouts set main_workout = $mobility_repair$<p class="tiptap-paragraph">🧽 <strong><u>Soft Tissue Preparation 5'</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph">Foam roll glutes and hip flexors (90 sec per side)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">Foam roll lats and upper back (60 sec per side)</p></li></ul><p class="tiptap-paragraph"></p><p class="tiptap-paragraph">🔥 <strong><u>Activation 15'</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph">3 {{exercise:bird-dog:Bird Dog}} (slow & controlled)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">3 {{exercise:cat-cow-stretch:Cat-Cow Stretch}}</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">3 {{exercise:1688:lunge with twist}}</p></li></ul><p class="tiptap-paragraph"></p><p class="tiptap-paragraph">💪 <strong><u>Main Workout (REPS & SETS)</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph">4 {{exercise:0583:lever kneeling twist}} (controlled twist)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">3 {{exercise:1604:world greatest stretch}} (full range of motion)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">3 {{exercise:forearm-plank:Forearm Plank}}</p></li></ul><p class="tiptap-paragraph">Rest 60-90 seconds between sets.</p><p class="tiptap-paragraph"></p><p class="tiptap-paragraph">⚡ <strong><u>Finisher (REPS & SETS)</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph">3 {{exercise:0979:band horizontal pallof press}}</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">3 {{exercise:0705:side bridge v. 2}}</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">3 {{exercise:0409:dumbbell single leg calf raise}} (light dumbbell)</p></li></ul><p class="tiptap-paragraph">Rest 45-60 seconds between sets.</p><p class="tiptap-paragraph"></p><p class="tiptap-paragraph">🧘 <strong><u>Cool Down 10'</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:1511:hamstring stretch}}</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:pigeon-stretch:Pigeon Stretch}}</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:1424:seated glute stretch}}</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph"><strong>Diaphragmatic Breathing (2 min):</strong> Lie supine, one hand on chest, one on belly. Slow inhale through nose (belly rises), slow exhale through mouth. Focus on calming nervous system.</p></li></ul>$mobility_repair$, updated_at = now() where id = 'WOD-MS-E-1778655003044';
update public.admin_workouts set main_workout = $mobility_repair$<div class="workout-content"><p class="tiptap-paragraph">🧽 <strong><u>Soft Tissue Preparation 5'</u></strong></p><p class="tiptap-paragraph">Use a foam roller or lacrosse ball to target tight areas: glutes, hamstrings, quads, and upper back. Spend approximately 60 seconds per area, focusing on deep breaths and sustained pressure on tender spots.</p><p class="tiptap-paragraph"></p><p class="tiptap-paragraph">🔥 <strong><u>Activation</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:bird-dog:Bird Dog}} - 2 sets x 10 reps per side (slow and controlled, focus on core engagement)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:cat-cow-stretch:Cat-Cow Stretch}} - 2 sets x 10 reps (synchronize with breath)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:glute-bridge:Glute Bridge}} - 2 sets x 12 reps (hold peak contraction for 2 seconds)</p></li></ul><p class="tiptap-paragraph"></p><p class="tiptap-paragraph">💪 <strong><u>Main Workout (REPS & SETS 30')</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:3645:single leg bridge with outstretched leg}} - 3 sets x 8-10 reps per side (3-1-1-0 tempo, rest 60s)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:0730:single leg platform slide}} - 3 sets x 10-12 reps per side (2-0-2-0 tempo, rest 60-90s)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:3699:shoulder tap}} - 3 sets x 12-15 reps per side (controlled, minimize hip movement, rest 45s)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:0705:side bridge v. 2}} - 3 sets x 10-12 reps per side (2-0-2-0 tempo, rest 60s)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:1604:world greatest stretch}} - 2 sets x 6-8 reps per side (hold each position for 3 seconds, rest 30s)</p></li></ul><p class="tiptap-paragraph"></p><p class="tiptap-paragraph">⚡ <strong><u>Finisher (For Time)</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:3665:power point plank}} - 2 sets to failure (maintain perfect form, rest 30s between sets)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:forearm-plank:Forearm Plank}} - 2 sets x 45-60 seconds (engage core, flat back)</p></li></ul><p class="tiptap-paragraph"></p><p class="tiptap-paragraph">🧘 <strong><u>Cool Down</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:1494:butterfly yoga pose}} - 2 sets x 30 seconds (deep breathing)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:1418:hug knees to chest}} - 2 sets x 30 seconds</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:1363:spine stretch}} - 2 sets x 30 seconds per side</p></li></ul></div>$mobility_repair$, updated_at = now() where id = 'FREE-int-mobility-stability-B-1777866802125';
update public.admin_workouts set main_workout = $mobility_repair$<p class="tiptap-paragraph">🧽 <strong><u>Soft Tissue Preparation 5'</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph">Foam roll glutes and hip flexors (60 seconds per side)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">Foam roll lats and thoracic spine (60 seconds per side)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">Lacrosse ball feet (60 seconds per foot) and hip (60 seconds per side)</p></li></ul><p class="tiptap-paragraph"></p><p class="tiptap-paragraph">🔥 <strong><u>Activation 15'</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:cat-cow-stretch:Cat-Cow Stretch}}</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:2329:spine twist}}</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:1428:wrist circles}}</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:bird-dog:Bird Dog}}</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:3561:glute bridge march}}</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:the-hundred:The Hundred}}</p></li></ul><p class="tiptap-paragraph"></p><p class="tiptap-paragraph">💪 <strong><u>Main Workout (REPS & SETS 30')</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:3419:l-sit on floor}} - 4 sets x 10-15 seconds hold, progressive increase (focus on active shoulders, straight legs)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:3296:front lever}}- 4 sets x 5-10 seconds hold (maintain strict form, engage core)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:1759:single leg squat (pistol) male}} - 3 sets x 5-8 reps per leg (controlled descent, stable ankle and hip)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:1775:side plank hip adduction}} - 3 sets x 8-12 reps per side (slow and controlled, emphasize inner thigh lift)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:v-up:V-Up}} - 3 sets x 10-15 reps (smooth, synchronized lift, controlled lowering)</p></li></ul><p class="tiptap-paragraph">Rest 60-90 seconds between sets.</p><p class="tiptap-paragraph"></p><p class="tiptap-paragraph">⚡ <strong><u>Finisher (REPS & SETS 20')</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:0705:side bridge v. 2}} - 3 sets x 8-10 reps (focus on controlled hip flexion, minimal swing)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:3663:reverse plank with leg lift}} - 3 sets x 6-8 reps per leg (maintain hip extension, smooth leg lift)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:3300:lean planche}}- 3 sets x 10-15 seconds hold (progressively lean forward, engage shoulders)</p></li></ul><p class="tiptap-paragraph">Rest 60 seconds between sets.</p><p class="tiptap-paragraph"></p><p class="tiptap-paragraph">🧘 <strong><u>Cool Down 10'</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:1418:hug knees to chest}}</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:1511:hamstring stretch}}</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:pigeon-stretch:Pigeon Stretch}}</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:1358:side lying floor stretch}}</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph"><strong>Diaphragmatic Breathing (2 min):</strong> Lie supine, one hand on chest, one on belly. Focus on slow, deep breaths, expanding the abdomen on inhale and contracting on exhale. Aim for complete relaxation.</p></li></ul>$mobility_repair$, up