update public.admin_workouts set main_workout = $mobility_repair$<p class="tiptap-paragraph">🧽 <strong><u>Soft Tissue Preparation 5'</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph">Foam roll glutes and hip flexors (60 sec per side)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">Foam roll adductors and abductors (45 sec per side)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">Focus on any tight spots around the hips and lower back.</p></li></ul><p class="tiptap-paragraph"></p><p class="tiptap-paragraph">🔥 <strong><u>Activation 10'</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph">3 {{exercise:cat-cow-stretch:Cat-Cow Stretch}} (controlled movement)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">3 {{exercise:bird-dog:Bird Dog}} (focus on stability)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">3 {{exercise:clamshell:Clamshell}} (slow and controlled)</p></li></ul><p class="tiptap-paragraph"></p><p class="tiptap-paragraph">💪 <strong><u>Main Workout (REPS & SETS)</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph">3 {{exercise:glute-bridge:Glute Bridge}} (pause at top)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">3 {{exercise:3147:pelvic tilt}} (slow and controlled)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">3 {{exercise:0710:side hip abduction}} (body weight)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">3 {{exercise:1494:butterfly yoga pose}} (body weight) (gentle stretch)</p></li></ul><p class="tiptap-paragraph">Rest 60-90 seconds between sets.</p><p class="tiptap-paragraph"></p><p class="tiptap-paragraph">⚡ <strong><u>Finisher (REPS & SETS)</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph">2 {{exercise:0865:lying leg-hip rai