update public.admin_workouts set main_workout = $mobility_repair$<p class="tiptap-paragraph">🧽 <strong><u>Soft Tissue Preparation 5'</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph">Lacrosse ball upper trap release (45 seconds per side)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">Foam roll hip flexors (45 seconds per side)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">Lacrosse ball glute trigger points (45 seconds per side)</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">Foam roll calves with pauses (30 seconds per leg)</p></li></ul><p class="tiptap-paragraph"></p><p class="tiptap-paragraph">🔥 <strong><u>Activation 10'</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph">2 rounds of: 10 {{exercise:3304:skin the cat}}, 5 Thread the Needle (each side), 10 Bird (alternating)</p></li></ul><p class="tiptap-paragraph"></p><p class="tiptap-paragraph">💪 <strong><u>Main Workout: Pillar Forge (40 minutes)</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:0979:band horizontal pallof press}} 4 sets x 20m (each arm), slow and controlled. Rest 60s between arms.</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:1717:cable squat row (with rope attachment)}} 4 sets x 8 reps (3-second hold at bottom). Rest 90s.</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:0551:kettlebell turkish get up (squat style)}} 3 sets x 3 reps (each side), focus on perfect form. Rest 90s between sides.</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:0979:band horizontal pallof press}} 3 sets x 10-12 reps (each side), ez barbell anti gravity press-rotation focus. Rest 60s.</p></li><li class="tiptap-list-item"><p class="tiptap-paragraph">{{exercise:1604:world greatest stretch}} 3 sets x 8 reps (each leg), controlled descent. Rest 60s between legs.</p></li></ul><p class="tiptap-paragraph"></p><p class="tiptap-paragraph">⚡ <strong><u>Finisher: Core Control Flow (10 minutes)</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph"><strong>Plank Variations Circuit:</strong> 3 rounds - 45s power point plank, 45s side bridge v. 2 (left), 45s bodyweight incline side plank. Rest 30s between rounds.</p></li></ul><p class="tiptap-paragraph"></p><p class="tiptap-paragraph">🧘 <strong><u>Cool Down 5'</u></strong></p><ul class="tiptap-bullet-list"><li class="tiptap-list-item"><p class="tiptap-paragraph">2 minutes {{exercise:1274:deep push up}}</p></li></ul>$mobility_repair$, updated_at = now() where id = 'WOD-MS-E-1769898605155';
